temperature = 22

if temperature > 30:
    print("It's hot — wear light clothes")
elif temperature > 20:
    print("It's pleasant — enjoy the weather")
elif temperature > 10:
    print("It's cool — bring a jacket")
else:
    print("It's cold — bundle up!")

# Output: It's pleasant — enjoy the weather

# One-liner (ternary) — for simple cases
status = "adult" if temperature >= 18 else "minor"
print(status)

const score = 85;

if (score >= 90) {
  console.log("Grade: A");
} else if (score >= 80) {
  console.log("Grade: B");
} else if (score >= 70) {
  console.log("Grade: C");
} else {
  console.log("Grade: F");
}
// Output: Grade: B

// Ternary operator
const pass = score >= 60 ? "Pass" : "Fail";
console.log(pass);   // "Pass"

