# break — exit the loop immediately
for n in range(10):
    if n == 5:
        break               # stops at 5 — prints 0,1,2,3,4
    print(n)

# continue — skip the rest of this iteration
for n in range(10):
    if n % 2 == 0:          # if n is even...
        continue            # ...skip it
    print(n)               # prints: 1, 3, 5, 7, 9

# for/else — else runs only if loop completed without break
for n in range(5):
    if n == 10:
        break
else:
    print("Loop completed without break")  # this runs
